/**
 * 60+ Industry Operating Systems for Nexus.
 *
 * Each industry has TWO modes:
 *   - mode1: stages to run for a NEW business (build from zero)
 *   - mode2: stages to run for an EXISTING business (audit + optimize)
 *
 * Every stage declares the agents it activates, the deliverables it produces,
 * and (optionally) whether CEO approval is required before advancing.
 * The CEO also gets a set of "Continuous Loop" questions that drive perpetual
 * mode once the linear stage sequence is exhausted.
 *
 * Stages are stored as ordered, with id/name/description/agents/deliverables.
 * The execution engine maps each stage to one or more execution tasks.
 */

export type IndustryMode = 'new' | 'existing';

export interface IndustryStage {
  id: string;
  name: string;
  description: string;
  agents: string[];
  deliverables: string[];
  approvalRequired?: boolean;
  ceoGate?: 'proceed' | 'pivot' | 'refine';
  taskTitles?: string[];
}

export interface IndustryOS {
  slug: string;
  displayName: string;
  icon: string;
  blurb: string;
  primaryAgents: string[];
  keyMetrics: string[];
  mode1: IndustryStage[];
  mode2: IndustryStage[];
  continuousLoopQuestions: string[];
}

const stage = (
  id: string,
  name: string,
  description: string,
  agents: string[],
  deliverables: string[],
  extra: Partial<IndustryStage> = {},
): IndustryStage => ({ id, name, description, agents, deliverables, ...extra });

export { stage as makeStage };

/* ===========================================================================
 *  Helpers to declare industries compactly.
 *  - newStages([...])   — Mode 1 stages (build a new business).
 *  - existingStages([...]) — Mode 2 stages (audit + optimize existing).
 *  - os(slug, name, icon, blurb, agents, metrics, m1, m2, loop) — build OS.
 * ========================================================================= */

const newStages = (...items: Array<[string, string, string[], string[]]>): IndustryStage[] =>
  items.map(([id, name, agents, deliverables]) => stage(id, name, name, agents, deliverables));

const existingStages = (...items: Array<[string, string, string[], string[]]>): IndustryStage[] =>
  items.map(([id, name, agents, deliverables]) => stage(id, name, name, agents, deliverables));

const os = (
  slug: string,
  displayName: string,
  icon: string,
  blurb: string,
  primaryAgents: string[],
  keyMetrics: string[],
  mode1: IndustryStage[],
  mode2: IndustryStage[],
  continuousLoopQuestions: string[],
): IndustryOS => ({ slug, displayName, icon, blurb, primaryAgents, keyMetrics, mode1, mode2, continuousLoopQuestions });

