export const ALL_INDUSTRY_OS: IndustryOS[] = [...INDUSTRY_OS, ...INDUSTRY_OS_EXTRA];

export function getIndustryOS(slug: string | undefined | null): IndustryOS | null {
  if (!slug) return null;
  const key = String(slug).toLowerCase().trim();
  return ALL_INDUSTRY_OS.find((i) => i.slug === key) ?? null;
}

/** Match by display name fuzzy or by alias. */
export function matchIndustryOS(input: string | undefined | null): IndustryOS | null {
  if (!input) return null;
  const key = String(input).toLowerCase().trim();
  return (
    ALL_INDUSTRY_OS.find((i) => i.slug === key) ??
    ALL_INDUSTRY_OS.find((i) => i.displayName.toLowerCase() === key) ??
    ALL_INDUSTRY_OS.find((i) => i.displayName.toLowerCase().includes(key) || key.includes(i.slug)) ??
    null
  );
}

